mapper.update:
update cart_item
set quantity = #{quantity},
    update_time = current_timestamp
where id = #{id}
  and user_id = #{userId}

update cart_item
set checked = #{checked},
    update_time = current_timestamp
where id = #{id}
  and user_id = #{userId}

mapper.delete:
delete from cart_item
where id = #{id}
  and user_id = #{userId}

delete from cart_item
where user_id = #{userId}
  and checked = 1
